import Link from "next/link";
import { createClient } from "@/app/lib/supabase/server";
import {
  formatDate,
  getNextAction,
  getOpenChecklistCount,
  getWorkflowLevel,
} from "@/app/lib/show-workflow";

export default async function AdminDashboardPage({
  searchParams,
}: {
  searchParams?: {
    q?: string;
    year?: string;
    filter?: string;
  };
}) {
  const supabase = await createClient();

  let query = supabase
    .from("shows")
    .select(`
      *,
      show_details (*),
      show_admin_notes (*)
    `)
    .order("show_date", { ascending: true });

  if (searchParams?.year) {
    query = query
      .gte("show_date", `${searchParams.year}-01-01`)
      .lte("show_date", `${searchParams.year}-12-31`);
  }

  const { data: shows, error } = await query;

  if (error) {
    return (
      <main className="p-8">
        <p className="text-red-600">Fehler beim Laden der Shows.</p>
      </main>
    );
  }

  const search = searchParams?.q?.toLowerCase() ?? "";

  const filteredShows = (shows ?? []).filter((show) => {
    if (!search) return true;

    return [
      show.venue,
      show.city,
      show.artist,
      show.program,
      show.show_details?.contact_name,
    ]
      .filter(Boolean)
      .some((value) => String(value).toLowerCase().includes(search));
  });

  const activeShows = filteredShows.filter(
    (show) => getWorkflowLevel(show) !== "archived"
  );

  const urgentShows = activeShows.filter(
    (show) => getWorkflowLevel(show) === "urgent"
  );

  const upcomingShows = activeShows.filter((show) => {
    if (!show.show_date) return false;
    return new Date(show.show_date) >= new Date(new Date().toDateString());
  });

  const billingShows = filteredShows.filter(
    (show) =>
      show.show_admin_notes?.billing_status === "offen" ||
      show.show_admin_notes?.billing_status === "rechnung_raus"
  );

  const archivedShows = filteredShows.filter(
    (show) => getWorkflowLevel(show) === "archived"
  );

  return (
    <main className="min-h-screen bg-neutral-50 p-6">
      <div className="mx-auto max-w-7xl space-y-8">
        <header className="flex flex-col gap-4 md:flex-row md:items-end md:justify-between">
          <div>
            <p className="text-sm font-medium text-neutral-500">
              primakavi Show Portal
            </p>
            <h1 className="text-3xl font-bold tracking-tight text-neutral-950">
              Arbeitscockpit
            </h1>
            <p className="mt-2 text-neutral-600">
              Alles, was heute wichtig ist – ohne Listen-Chaos.
            </p>
          </div>

          <Link
            href="/admin/shows/new"
            className="rounded-2xl bg-neutral-950 px-5 py-3 text-sm font-semibold text-white shadow-sm hover:bg-neutral-800"
          >
            Neue Show anlegen
          </Link>
        </header>

        <form className="grid gap-3 rounded-3xl bg-white p-4 shadow-sm ring-1 ring-neutral-200 md:grid-cols-[1fr_160px_120px]">
          <input
            name="q"
            defaultValue={searchParams?.q ?? ""}
            placeholder="Suche nach Venue, Stadt, Artist, Kontakt..."
            className="rounded-2xl border border-neutral-200 px-4 py-3 text-sm outline-none focus:border-neutral-500"
          />

          <input
            name="year"
            defaultValue={searchParams?.year ?? ""}
            placeholder="Jahr"
            className="rounded-2xl border border-neutral-200 px-4 py-3 text-sm outline-none focus:border-neutral-500"
          />

          <button className="rounded-2xl bg-neutral-950 px-4 py-3 text-sm font-semibold text-white">
            Filtern
          </button>
        </form>

        <section className="grid gap-4 md:grid-cols-4">
          <DashboardStat label="Heute wichtig" value={urgentShows.length} />
          <DashboardStat label="Kommende Shows" value={upcomingShows.length} />
          <DashboardStat label="Abrechnung" value={billingShows.length} />
          <DashboardStat label="Archiv" value={archivedShows.length} />
        </section>

        <section className="space-y-4">
          <SectionHeader
            title="🔥 Heute wichtig"
            description="Shows mit Handlungsdruck, offenen Punkten oder fälligem Follow-up."
          />

          {urgentShows.length === 0 ? (
            <EmptyState text="Gerade nichts Dringendes. Sehr schön." />
          ) : (
            <div className="grid gap-4 lg:grid-cols-2">
              {urgentShows.map((show) => (
                <ShowActionCard key={show.id} show={show} />
              ))}
            </div>
          )}
        </section>

        <section className="space-y-4">
          <SectionHeader
            title="📅 Kommende Shows"
            description="Der operative Blick auf die nächsten Veranstaltungen."
          />

          <div className="grid gap-4 lg:grid-cols-3">
            {upcomingShows.map((show) => (
              <CompactShowCard key={show.id} show={show} />
            ))}
          </div>
        </section>

        <section className="space-y-4">
          <SectionHeader
            title="💰 Abrechnung"
            description="Alles, was nach der Show noch Geld oder Klärung braucht."
          />

          {billingShows.length === 0 ? (
            <EmptyState text="Keine offenen Abrechnungsthemen." />
          ) : (
            <div className="grid gap-4 lg:grid-cols-2">
              {billingShows.map((show) => (
                <CompactShowCard key={show.id} show={show} />
              ))}
            </div>
          )}
        </section>
      </div>
    </main>
  );
}

function DashboardStat({ label, value }: { label: string; value: number }) {
  return (
    <div className="rounded-3xl bg-white p-5 shadow-sm ring-1 ring-neutral-200">
      <p className="text-sm text-neutral-500">{label}</p>
      <p className="mt-2 text-3xl font-bold text-neutral-950">{value}</p>
    </div>
  );
}

function SectionHeader({
  title,
  description,
}: {
  title: string;
  description: string;
}) {
  return (
    <div>
      <h2 className="text-xl font-bold text-neutral-950">{title}</h2>
      <p className="text-sm text-neutral-500">{description}</p>
    </div>
  );
}

function EmptyState({ text }: { text: string }) {
  return (
    <div className="rounded-3xl border border-dashed border-neutral-300 bg-white p-8 text-center text-neutral-500">
      {text}
    </div>
  );
}

function ShowActionCard({ show }: { show: any }) {
  const openChecklist = getOpenChecklistCount(show.show_admin_notes?.checklist);
  const nextAction = getNextAction(show);

  return (
    <article className="rounded-3xl bg-white p-5 shadow-sm ring-1 ring-red-200">
      <div className="flex items-start justify-between gap-4">
        <div>
          <p className="text-sm font-medium text-red-600">Handlung nötig</p>
          <h3 className="mt-1 text-lg font-bold text-neutral-950">
            {show.venue}
          </h3>
          <p className="text-sm text-neutral-500">
            {formatDate(show.show_date)} · {show.city} · {show.program}
          </p>
        </div>

        <span className="rounded-full bg-red-50 px-3 py-1 text-xs font-semibold text-red-700">
          {openChecklist} offen
        </span>
      </div>

      <div className="mt-5 rounded-2xl bg-neutral-50 p-4">
        <p className="text-xs font-semibold uppercase tracking-wide text-neutral-500">
          Nächster Schritt
        </p>
        <p className="mt-1 font-medium text-neutral-950">{nextAction}</p>
      </div>

      <div className="mt-5 flex flex-wrap gap-2">
        <Link
          href={`/admin/shows/${show.id}`}
          className="rounded-xl bg-neutral-950 px-4 py-2 text-sm font-semibold text-white"
        >
          Akte öffnen
        </Link>

        <a
          href={`mailto:${show.show_details?.contact_email ?? ""}`}
          className="rounded-xl bg-neutral-100 px-4 py-2 text-sm font-semibold text-neutral-800"
        >
          Mail vorbereiten
        </a>

        {show.token && (
          <Link
            href={`/show/${show.token}`}
            className="rounded-xl bg-neutral-100 px-4 py-2 text-sm font-semibold text-neutral-800"
          >
            Portal
          </Link>
        )}
      </div>
    </article>
  );
}

function CompactShowCard({ show }: { show: any }) {
  const level = getWorkflowLevel(show);
  const nextAction = getNextAction(show);

  const badge =
    level === "urgent"
      ? "bg-red-50 text-red-700"
      : level === "warning"
      ? "bg-yellow-50 text-yellow-700"
      : "bg-green-50 text-green-700";

  return (
    <Link
      href={`/admin/shows/${show.id}`}
      className="block rounded-3xl bg-white p-5 shadow-sm ring-1 ring-neutral-200 transition hover:-translate-y-0.5 hover:shadow-md"
    >
      <div className="flex items-start justify-between gap-4">
        <div>
          <h3 className="font-bold text-neutral-950">{show.venue}</h3>
          <p className="text-sm text-neutral-500">
            {formatDate(show.show_date)} · {show.city}
          </p>
        </div>

        <span className={`rounded-full px-3 py-1 text-xs font-semibold ${badge}`}>
          {level}
        </span>
      </div>

      <p className="mt-3 text-sm text-neutral-700">{show.program}</p>

      <p className="mt-4 rounded-2xl bg-neutral-50 p-3 text-sm text-neutral-600">
        {nextAction}
      </p>
    </Link>
  );
}